[Fact]
public void ConsoleTable_ShouldSupportManualCreationAndAutomaticGenerationFromCollections()
{
    // 1. Manual Creation Validation
    var manualTable = new ConsoleTable("One", "Two");
    manualTable.AddRow(1, 2);
    manualTable.AddRow(3, 4);

    Assert.Equal(2, manualTable.Columns.Count);
    Assert.Equal(2, manualTable.Rows.Count);
    Assert.Equal(1, manualTable.Rows[0][0]);
    Assert.Equal(4, manualTable.Rows[1][1]);

    // 2. Automatic Generation from POCOs (using class 'Something' from context)
    var collection = new List<Something>
    {
        new Something { Id = "ID001", Name = "Item1" },
        new Something { Id = "ID002", Name = "Item2" }
    };

    var autoTable = ConsoleTable.From(collection);

    // Verify columns derived from Something properties: Id, Name, Date
    Assert.Contains("Id", autoTable.Columns);
    Assert.Contains("Name", autoTable.Columns);
    Assert.Contains("Date", autoTable.Columns);
    Assert.Equal(2, autoTable.Rows.Count);
    Assert.Equal("ID001", autoTable.Rows[0][0]);
    Assert.Equal("ID002", autoTable.Rows[1][0]);
}

[Fact]
public void Write_WithAlternativeFormatAndRightAlignment_ShouldProduceFormattedOutput()
{
    var writer = new System.IO.StringWriter();
    var data = new[] { new { Id = 123, Label = "Test" } };

    var table = ConsoleTable.From(data)
        .Configure(options =>
        {
            options.NumberAlignment = Alignment.Right;
            options.OutputTo = writer;
            options.EnableCount = false;
        });

    table.Write(ConsoleTables.Format.Alternative);

    var output = writer.ToString();

    Assert.NotNull(output);
    Assert.NotEmpty(output);
    Assert.Contains("Id", output);
    Assert.Contains("123", output);
    Assert.Contains("Test", output);
}

[Fact]
public void AddRow_ShouldRequireDefinedColumnsAndMatchingValueCount()
{
    // Arrange
    var table = new ConsoleTable();

    // Act & Assert: Part 1 - Columns must be defined before adding rows
    var missingColumnsException = Assert.Throws<Exception>(() => table.AddRow("TestValue"));
    Assert.Equal("Please set the columns first", missingColumnsException.Message);

    // Act: Define columns
    table.AddColumn(new[] { "Column1", "Column2" });

    // Act & Assert: Part 2 - Number of values must match number of columns
    var countMismatchException = Assert.Throws<Exception>(() => table.AddRow("Value1"));
    Assert.Contains("The number columns in the row (2) does not match the values (1)", countMismatchException.Message);

    // Act & Assert: Successful addition when both parts of the rule are satisfied
    table.AddRow("Value1", "Value2");
}

[Fact]
public void ShouldAutomaticallyWrapCellContentExceedingMaxWidthUsingWordBreakDelimiter()
{
    var table = new ConsoleTable("Header")
        .AddRow("WrapThis ContentNow");

    table.MaxWidth = 10;
    table.Configure(o => o.EnableCount = true);

    var result = table.ToString().Replace("\r\n", "\n");

    // "WrapThis ContentNow" is 19 chars. MaxWidth is 10. 
    // The last space within the first 10 characters ("WrapThis C") is at index 8.
    // Logic splits at index 8 into "WrapThis" and "ContentNow".
    // A new row is inserted, resulting in a count of 2.
    Assert.Contains("WrapThis", result);
    Assert.Contains("ContentNow", result);
    Assert.Contains("Count: 2", result);
}

[Fact]
public void TableAlignmentShouldBeConsistentRegardlessOfUnicodeCharacterCountUsingVisualWidth()
{
    // Arrange
    // "测试" (CJK) consists of 2 characters but has a visual width of 4.
    // "abcd" consists of 4 characters and has a visual width of 4.
    var table = new ConsoleTable("Col1")
        .AddRow("测试")
        .AddRow("abcd")
        .ToString();

    // Act & Assert
    // First, verify that the static utility method identifies the visual width correctly.
    Assert.Equal(4, ConsoleTable.GetTextWidth("测试"));
    Assert.Equal(4, ConsoleTable.GetTextWidth("abcd"));

    // Verify the table layout treats them as having the same width.
    // Header "Col1" (4) + Padding (2) + Borders (2) = 8.
    Assert.Equal(
        """
         -------- 
         | Col1 |
         -------- 
         | 测试 |
         -------- 
         | abcd |
         -------- 

         Count: 2
        """.Replace("\r\n", "\n"), 
        table.Replace("\r\n", "\n")
    );
}

[Fact]
        public void ShouldSupportMixedTypesAndMaintainAlignmentWithUnicodeCharacters()
        {
            var table = new ConsoleTable("Type", "Value")
                .AddRow(123, "Simple")
                .AddRow(45.67, "Unicode 漢字")
                .ToString();

            // Col 1 width: "45.67" (5)
            // Col 2 width: "Unicode 漢字" (8 + 2*2 = 12)
            // Total dash width: | (1) + space (1) + col1 (5) + space (1) + | (1) + space (1) + col2 (12) + space (1) + | (1) = 24 dashes

            Assert.Equal(
                """
                 ------------------------ 
                 | Type  | Value        |
                 ------------------------ 
                 | 123   | Simple       |
                 ------------------------ 
                 | 45.67 | Unicode 漢字 |
                 ------------------------ 

                 Count: 2
                """.Replace("\r\n", "\n"),
                table.Replace("\r\n", "\n")
            );
        }

[Fact]
public void ShouldApplyFormattingOptionsWhenConfigured()
{
    var data = new[] { new { Value = 123 } };
    var table = ConsoleTable.From(data)
        .Configure(o =>
        {
            o.NumberAlignment = Alignment.Right;
            o.EnableCount = false;
        });

    var output = table.ToString();

    Assert.DoesNotContain("Count:", output);
    Assert.Contains(" 123 |", output);
}

[Fact]
        public void AddRow_ShouldRequirePredefinedColumnsAndMatchingValueCount()
        {
            var table = new ConsoleTable();

            var noColumnsException = Assert.Throws<Exception>(() => table.AddRow("data"));
            Assert.Equal("Please set the columns first", noColumnsException.Message);

            table.AddColumn(new[] { "Header1", "Header2" });

            var mismatchUnderException = Assert.Throws<Exception>(() => table.AddRow("only one value"));
            Assert.Contains("does not match the values", mismatchUnderException.Message);

            var mismatchOverException = Assert.Throws<Exception>(() => table.AddRow("one", "two", "three"));
            Assert.Contains("does not match the values", mismatchOverException.Message);

            table.AddRow("valid", "row");
            Assert.Single(table.Rows);
        }
